//
// Shared API-shape test fixtures. Service tests reference these
// builders instead of inlining literal `{accessToken: 'test-...'}`
// objects and `expect.objectContaining({headers: ...})` blocks — this
// eliminates the cross-service param/header duplication SonarQube
// flags and keeps one place to update if the convention changes.

/**
 * Build a params object matching the `test-<key>` convention every
 * generated service test uses.
 *
 *   testParams(['accessToken', 'userId'])
 *   // → { accessToken: 'test-accessToken', userId: 'test-userId' }
 */
export function testParams<K extends string>(keys: readonly K[]): Record<K, string> {
  const out: Record<string, string> = {};
  for (const k of keys) {
    out[k] = `test-${k}`;
  }
  return out as Record<K, string>;
}

export interface TestCallOpts {
  /** Param name supplying the bearer token: emits `'Bearer test-<auth>'`. */
  auth?: string;
  /** Content-Type header to assert (matched verbatim). */
  contentType?: string;
  /** Accept header to assert (matched verbatim). */
  accept?: string;
  /** If true, inserts `expect.anything()` between url and options for the body arg. */
  withBody?: boolean;
}

/**
 * Build the args tuple passed to `expect(client.<verb>).toHaveBeenCalledWith(...)`.
 *
 *   testCallArgs('/users/test-userId', { auth: 'accessToken', withBody: true })
 *   // → [
 *   //     '/users/test-userId',
 *   //     expect.anything(),
 *   //     expect.objectContaining({
 *   //       headers: expect.objectContaining({ Authorization: 'Bearer test-accessToken' }),
 *   //     }),
 *   //   ]
 */
export function testCallArgs(url: string, opts: TestCallOpts = {}): unknown[] {
  const headers: Record<string, string> = {};
  if (opts.auth) headers.Authorization = `Bearer test-${opts.auth}`;
  if (opts.contentType) headers['Content-Type'] = opts.contentType;
  if (opts.accept) headers.accept = opts.accept;
  const headerExpect =
    Object.keys(headers).length > 0
      ? expect.objectContaining(headers)
      : expect.anything();
  const optionsObj = expect.objectContaining({ headers: headerExpect });
  return opts.withBody
    ? [url, expect.anything(), optionsObj]
    : [url, optionsObj];
}
